const hamburger=document.querySelector(".hamburger");const navLinks=document.querySelector(".nav-links");const links=document.querySelectorAll(".nav-links a");hamburger.addEventListener("click",()=>{hamburger.classList.toggle("active");navLinks.classList.toggle("active")});links.forEach(e=>{e.addEventListener("click",()=>{hamburger.classList.remove("active");navLinks.classList.remove("active")})});const navbar=document.querySelector(".navbar");window.addEventListener("scroll",()=>{if(window.scrollY>50){navbar.classList.add("scrolled")}else{navbar.classList.remove("scrolled")}let e="";const t=document.querySelectorAll("section");t.forEach(t=>{const n=t.offsetTop;const s=t.clientHeight;if(pageYOffset>=n-s/3){e=t.getAttribute("id")}});links.forEach(t=>{t.classList.remove("active");if(t.getAttribute("href").includes(e)&&e!==""){t.classList.add("active")}})});const observerOptions={root:null,rootMargin:"0px",threshold:.15};const observer=new IntersectionObserver((e,t)=>{e.forEach(e=>{if(e.isIntersecting){e.target.classList.add("show");t.unobserve(e.target)}})},observerOptions);const hiddenElements=document.querySelectorAll(".hidden");hiddenElements.forEach(e=>observer.observe(e));const track=document.getElementById("carousel-track");const prevBtn=document.querySelector(".prev-btn");const nextBtn=document.querySelector(".next-btn");if(track){const e=Array.from(track.children);e.forEach(e=>{const t=e.cloneNode(true);track.appendChild(t)});let t=0;let n=false;track.addEventListener("mouseenter",()=>n=true);track.addEventListener("mouseleave",()=>n=false);if(prevBtn&&nextBtn){prevBtn.addEventListener("mouseenter",()=>n=true);prevBtn.addEventListener("mouseleave",()=>n=false);nextBtn.addEventListener("mouseenter",()=>n=true);nextBtn.addEventListener("mouseleave",()=>n=false)}function scrollCarousel(){if(!n){t+=1;const e=track.scrollWidth/2;if(t>=e){t=0}else if(t<0){t=e-1}track.style.transform=`translateX(-${t}px)`}requestAnimationFrame(scrollCarousel)}scrollCarousel();if(prevBtn&&nextBtn){nextBtn.addEventListener("click",()=>{const e=parseFloat(window.getComputedStyle(track).gap)||0;const n=track.children[0].offsetWidth>0?track.children[0].offsetWidth+e:0;if(n>0){t+=n;const e=track.scrollWidth/2;if(t>=e){t=t%e}track.style.transform=`translateX(-${t}px)`}});prevBtn.addEventListener("click",()=>{const e=parseFloat(window.getComputedStyle(track).gap)||0;const n=track.children[0].offsetWidth>0?track.children[0].offsetWidth+e:0;if(n>0){t-=n;if(t<0){t=track.scrollWidth/2-Math.abs(t)}track.style.transform=`translateX(-${t}px)`}})}}function switchTab(e){const t=document.getElementById("experience-tab");const n=document.getElementById("education-tab");const s=document.querySelectorAll(".toggle-btn");s.forEach(e=>e.classList.remove("active"));t.style.display="none";n.style.display="none";if(e==="experience"){t.style.display="flex";s[0].classList.add("active")}else{n.style.display="flex";s[1].classList.add("active")}}const heroBtns=document.querySelectorAll(".cta-buttons .btn");heroBtns.forEach(e=>{e.addEventListener("click",function(){heroBtns.forEach(e=>{e.classList.remove("primary");e.classList.add("secondary")});this.classList.remove("secondary");this.classList.add("primary")})});const typingElement=document.querySelector(".typing-text");if(typingElement){const s=typingElement.textContent;typingElement.textContent="";let r=0;setTimeout(()=>{const e=setInterval(()=>{if(r<s.length){typingElement.textContent+=s.charAt(r);r++}else{clearInterval(e);typingElement.style.borderRight="none";typingElement.style.animation="none"}},120)},800)}const contactForm=document.querySelector(".contact-form");const formFeedback=document.getElementById("form-feedback");if(contactForm&&formFeedback){contactForm.addEventListener("submit",function(e){e.preventDefault();if(!contactForm.checkValidity()){formFeedback.textContent="Please fill out all required fields with valid information (e.g. a valid email address).";formFeedback.classList.remove("hidden-msg","success");formFeedback.classList.add("error");return}const t=contactForm.querySelector(".submit-btn");const n=t.textContent;t.textContent="Sending...";t.disabled=true;const s=new FormData(contactForm);fetch("/",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams(s).toString()}).then(()=>{formFeedback.textContent="Thank you! Your message has been sent successfully.";formFeedback.classList.remove("hidden-msg","error");formFeedback.classList.add("success");contactForm.reset();setTimeout(()=>{formFeedback.classList.add("hidden-msg")},5e3)}).catch(e=>{formFeedback.textContent="Oops! There was a problem submitting your form.";formFeedback.classList.remove("hidden-msg","success");formFeedback.classList.add("error")}).finally(()=>{t.textContent=n;t.disabled=false})})}